// Redis Token Bucket (Node.js)

async function rateLimit(userId, limit = 100, window = 60) {

  const key = `rate:${userId}`;

  const now = Date.now();

  const [count] = await redis.multi()

    .incr(key)

    .expire(key, window)

    .exec();

  if (count > limit) {

    throw new Error('Rate limit exceeded');

  }

  return { remaining: limit - count };

}

// SSE (Server-Sent Events) in Node.js

app.get('/events', (req, res) => {

  res.setHeader('Content-Type', 'text/event-stream');

  res.setHeader('Cache-Control', 'no-cache');

  const interval = setInterval(() => {

    res.write(`data: ${JSON.stringify({ time: Date.now() })}\n\n`);

  }, 1000);

  req.on('close', () => clearInterval(interval));

});

// Client

const es = new EventSource('/events');

es.onmessage = (event) => console.log(JSON.parse(event.data));

gRPC flow:

  1. Define .proto file (Interface Definition Language)

  2. Generate code in any language

  3. Server implements generated interface

  4. Client uses generated stub

// user.proto

syntax = 'proto3';

service UserService {

  rpc GetUser(GetUserRequest) returns (User) {}

  rpc ListUsers(ListUsersRequest) returns (stream User) {}  // streaming!

  rpc CreateUser(stream CreateUserRequest) returns (User) {} // client stream

  rpc Chat(stream ChatMessage) returns (stream ChatMessage) {} // bidirectional

  }

message User {

  int32 id = 1;

  string name = 2;

  string email = 3;

  }

gRPC vs REST performance:

  Protobuf 5-10x smaller than JSON

  HTTP/2 multiplexing

  -> gRPC ~7x faster than REST

Content negotiation headers:

  Client: Accept: application/json, text/html;q=0.9, */*;q=0.8

  Server: Content-Type: application/json

  Client: Accept-Encoding: gzip, deflate, br

  Server: Content-Encoding: gzip

  Client: Accept-Language: vi-VN, vi;q=0.9, en-US;q=0.8

  Server: Content-Language: vi

// Express content negotiation

app.get('/data', (req, res) => {

  res.format({

    'application/json': () => res.json(data),

    'text/html':        () => res.send(renderHTML(data)),

    'text/csv':         () => res.send(toCSV(data))

  });

});

TCP Keep-Alive:

  Sends probe packets when connection idle

  Detect dead connections

  Linux defaults: 7200s idle, 75s interval, 9 probes

  Node.js:

  const agent = new https.Agent({

    keepAlive: true,

    maxSockets: 50,

    keepAliveMsecs: 30000

  });

Connection Pooling (PostgreSQL example):

  Without pool: each query creates TCP connection (expensive!)

  With pool: reuse existing connections

  const pool = new Pool({

    max: 10,           // max 10 connections

    min: 2,            // keep 2 idle

    idleTimeoutMillis: 30000,

    connectionTimeoutMillis: 2000

  });
